class User:
    def __init__(self, name, email, is_premium=False):
        self.name = name
        self.email = email
        self.is_premium = is_premium

    def display_name(self):
        prefix = "[P] " if self.is_premium else ""
        return f"{prefix}{self.name}"

    def to_dict(self):
        return {
            "name": self.name,
            "email": self.email,
            "is_premium": self.is_premium,
        }

